/* Base styles (apply to all viewports) */
.container {
  padding: 16px;
  max-width: 100%;
}

.grid {
  display: grid;
  grid-template-columns: 1fr;
  gap: 16px;
}

/* Tablet and up (min-width: 768px) */
@media (min-width: 768px) {
  .container {
    padding: 24px;
    max-width: 768px;
    margin: 0 auto;
  }
  .grid {
    grid-template-columns: repeat(2, 1fr);
  }
}

/* Desktop and up (min-width: 1024px) */
@media (min-width: 1024px) {
  .container {
    max-width: 1024px;
  }
  .grid {
    grid-template-columns: repeat(3, 1fr);
    gap: 24px;
  }
}

/* AND: both conditions must be true */
@media (min-width: 768px) and (max-width: 1023px) {
  /* Tablet only */
  .sidebar { display: none; }
}

/* OR: comma-separated (either condition) */
@media (max-width: 640px), (orientation: landscape) and (max-height: 500px) {
  /* Small screens OR short landscape devices */
  .hero { min-height: 50vh; }
}

/* NOT: negate the entire query */
@media not print {
  /* Everything except print */
  .no-print { display: block; }
}

/* Modern range syntax (well-supported) */
@media (width >= 768px) {
  /* Same as min-width: 768px */
  .card { flex-direction: row; }
}

@media (400px <= width <= 800px) {
  /* Width between 400px and 800px */
  .banner { font-size: 1.25rem; }
}

/* Dark mode preference */
@media (prefers-color-scheme: dark) {
  :root {
    --bg: #0f172a;
    --text: #f8fafc;
    --border: #334155;
  }
  body {
    background: var(--bg);
    color: var(--text);
  }
}

/* Reduced motion preference */
@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    transition-duration: 0.01ms !important;
  }
}

/* High-resolution displays */
@media (min-resolution: 2dppx) {
  .logo {
    background-image: url('/logo@2x.png');
  }
}

/* Hover capability (touchscreen vs mouse) */
@media (hover: hover) {
  .button:hover {
    background: #2563eb;
  }
}

/* Print styles */
@media print {
  .navbar, .footer, .sidebar { display: none; }
  body { font-size: 12pt; }
}

/* Base: Mobile (single column, stacked) */
.page {
  display: flex;
  flex-direction: column;
  min-height: 100vh;
}

.main-content {
  padding: 16px;
  order: 1;
}

.sidebar {
  padding: 16px;
  background: #f8fafc;
  order: 2;
}

.hero-title {
  font-size: 1.5rem;
  line-height: 1.3;
}

/* Tablet: side-by-side layout */
@media (min-width: 768px) {
  .page {
    flex-direction: row;
  }
  .main-content {
    flex: 1;
    padding: 24px;
    order: 1;
  }
  .sidebar {
    width: 280px;
    padding: 24px;
    order: 2;
  }
  .hero-title {
    font-size: 2rem;
  }
}

/* Desktop: wider with more spacing */
@media (min-width: 1024px) {
  .page {
    max-width: 1200px;
    margin: 0 auto;
  }
  .sidebar {
    width: 320px;
  }
  .hero-title {
    font-size: 2.5rem;
    line-height: 1.2;
  }
}

/* Mobile: hamburger menu (collapsed by default) */
.nav-links {
  display: none;
  flex-direction: column;
  background: #1e293b;
}
.nav-links.open {
  display: flex;
}
.nav-links a {
  padding: 14px 20px;
  color: white;
  text-decoration: none;
  border-bottom: 1px solid #334155;
}
.menu-toggle {
  display: block;
  padding: 12px 16px;
  background: #1e293b;
  color: white;
  border: none;
  font-size: 1.25rem;
  cursor: pointer;
}

/* Tablet+: show full nav, hide toggle */
@media (min-width: 768px) {
  .menu-toggle {
    display: none;
  }
  .nav-links {
    display: flex;
    flex-direction: row;
  }
  .nav-links a {
    border-bottom: none;
    padding: 16px 20px;
  }
  .nav-links a:hover {
    background: #334155;
  }
}

/* Mobile: prioritize content over sidebar */
.layout {
  display: flex;
  flex-direction: column;
}
.content {
  order: 1; /* Content first on mobile */
  padding: 16px;
}
.sidebar-left {
  order: 2; /* Sidebar below content on mobile */
  padding: 16px;
  background: #f1f5f9;
}
.sidebar-right {
  order: 3;
  padding: 16px;
  background: #f8fafc;
}

/* Desktop: three-column layout with sidebars on sides */
@media (min-width: 1024px) {
  .layout {
    flex-direction: row;
  }
  .sidebar-left {
    order: 1;
    width: 200px;
  }
  .content {
    order: 2;
    flex: 1;
    padding: 24px;
  }
  .sidebar-right {
    order: 3;
    width: 250px;
  }
}

/* DESKTOP-FIRST (avoid this) */
.card-grid-desktop {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 24px;
}
@media (max-width: 1023px) {
  .card-grid-desktop {
    grid-template-columns: repeat(2, 1fr);
  }
}
@media (max-width: 639px) {
  .card-grid-desktop {
    grid-template-columns: 1fr;
    gap: 12px;
  }
}

/* MOBILE-FIRST (prefer this) */
.card-grid-mobile {
  display: grid;
  grid-template-columns: 1fr;
  gap: 12px;
}
@media (min-width: 640px) {
  .card-grid-mobile {
    grid-template-columns: repeat(2, 1fr);
  }
}
@media (min-width: 1024px) {
  .card-grid-mobile {
    grid-template-columns: repeat(4, 1fr);
    gap: 24px;
  }
}

/* Full-screen hero section */
.hero {
  width: 100vw;
  height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  background: #1e293b;
  color: white;
}

/* Half-viewport sections */
.split-left {
  width: 50vw;
  height: 100vh;
  float: left;
}
.split-right {
  width: 50vw;
  height: 100vh;
  float: left;
}

/* Responsive font sizing with vmin */
.responsive-title {
  font-size: 5vmin; /* Scales with the smaller viewport dimension */
}

/* Square element that adapts to viewport */
.viewport-square {
  width: 30vmin;
  height: 30vmin; /* Always a perfect square */
}

/* PROBLEM: 100vh on mobile can cause overflow */
.hero-broken {
  height: 100vh; /* May be taller than visible area on mobile */
  /* Browser toolbar hides part of the content */
}

/* SOLUTION 1: Use dvh (dynamic viewport height) */
.hero-dvh {
  height: 100dvh; /* Adjusts as toolbars appear/disappear */
}

/* SOLUTION 2: Use svh (small viewport height) */
.hero-svh {
  height: 100svh; /* Always fits even with toolbars shown */
}

/* SOLUTION 3: Fallback for older browsers */
.hero-fallback {
  height: 100vh;              /* Fallback */
  height: 100dvh;             /* Modern override */
}

/* SOLUTION 4: JavaScript fallback */
/* Set --vh custom property via JS:
   document.documentElement.style
     .setProperty('--vh', window.innerHeight * 0.01 + 'px');
*/
.hero-js {
  height: calc(var(--vh, 1vh) * 100);
}

/* Fluid font sizes that scale between min and max */
h1 {
  /* Minimum 1.5rem, scales with 4vw, maximum 3.5rem */
  font-size: clamp(1.5rem, 4vw, 3.5rem);
}

h2 {
  font-size: clamp(1.25rem, 3vw, 2.5rem);
}

p {
  font-size: clamp(1rem, 1.5vw, 1.25rem);
  line-height: 1.7;
}

/* Fluid spacing */
.section {
  padding: clamp(24px, 5vw, 80px);
}

/* Fluid container width */
.container {
  width: clamp(320px, 90vw, 1200px);
  margin: 0 auto;
}

/* Without clamp (older approach) */
.legacy-title {
  font-size: calc(16px + 2vw);
  /* Problem: no minimum or maximum cap */
}

/* Small viewport height: toolbars visible (smallest) */
.section-svh {
  min-height: 100svh;
  /* Content always fits without scrolling */
  /* Good for: landing page hero sections */
}

/* Large viewport height: toolbars hidden (largest) */
.section-lvh {
  min-height: 100lvh;
  /* Fills the full space when toolbars collapse */
  /* Good for: background images, decorative sections */
}

/* Dynamic viewport height: tracks actual visible area */
.section-dvh {
  min-height: 100dvh;
  /* Updates in real time as toolbars change */
  /* Good for: most full-height layouts */
}

/* Combining with other units */
.sticky-footer {
  min-height: 100dvh;
  display: flex;
  flex-direction: column;
}
.sticky-footer main {
  flex: 1;
}
.sticky-footer footer {
  /* Footer sticks to the actual bottom of the visible area */
}

/* Width variants also exist */
.full-dynamic {
  width: 100dvw;
  height: 100dvh;
}
